<?php
namespace App\Modules\Hr\Engagement\Actions;
use App\Modules\Hr\Core\Services\HrAuditService; use App\Modules\Hr\Core\Services\TenantContext; use App\Modules\Hr\Engagement\Models\HrRecognition; use App\Modules\Hr\Personnel\Models\HrEmployee;
class GiveRecognitionAction { public function __construct(private HrAuditService $audit){} public function execute(HrEmployee $sender,HrEmployee $recipient,string $message,string $category='thanks',bool $isPublic=true):HrRecognition{$tenant=app(TenantContext::class)->getId();abort_unless(auth()->user()?->hasHrPermission('hr.engagement.view'),403);abort_unless($sender->legal_entity_id===$tenant&&$recipient->legal_entity_id===$tenant&&$sender->user_id===auth()->id(),404);abort_if($sender->id===$recipient->id||blank($message)||mb_strlen($message)>1000,422);$category=in_array($category,['thanks','teamwork','innovation','customer','leadership'],true)?$category:'thanks';$row=HrRecognition::create(['legal_entity_id'=>$tenant,'sender_employee_id'=>$sender->id,'recipient_employee_id'=>$recipient->id,'category'=>$category,'message'=>trim($message),'is_public'=>$isPublic,'recognized_at'=>now()]);$this->audit->log('engagement_recognition_given',$row,null,['category'=>$category,'public'=>$isPublic]);return $row;} }
